import json
import os
import time
import threading
from datetime import datetime, timedelta

class DiskCache:
    def __init__(self, cache_dir='cache', default_expiration_minutes=60):
        self.cache_dir = cache_dir
        self.default_expiration_seconds = default_expiration_minutes * 60
        os.makedirs(self.cache_dir, exist_ok=True)
        self.lock = threading.Lock() # For file system operations

    def _get_filepath(self, key):
        # Sanitize key for use as a filename
        filename = "".join(c for c in key if c.isalnum() or c in (' ', '.', '_')).rstrip()
        if not filename:
            filename = "default_cache_entry" # Fallback for completely invalid keys
        return os.path.join(self.cache_dir, f"{filename}.json")

    def set(self, key, data, expiration_seconds=None):
        expiration_seconds = expiration_seconds if expiration_seconds is not None else self.default_expiration_seconds
        expires_at = (datetime.now() + timedelta(seconds=expiration_seconds)).isoformat()

        cache_entry = {
            "expires_at": expires_at,
            "data": data
        }

        filepath = self._get_filepath(key)
        with self.lock:
            try:
                with open(filepath, 'w') as f:
                    json.dump(cache_entry, f)
                return True
            except IOError as e:
                print(f"Error writing to cache file {filepath}: {e}")
                return False

    def get(self, key):
        filepath = self._get_filepath(key)
        with self.lock:
            if not os.path.exists(filepath):
                return None

            try:
                with open(filepath, 'r') as f:
                    cache_entry = json.load(f)

                expires_at_str = cache_entry.get("expires_at")
                if expires_at_str:
                    expires_at = datetime.fromisoformat(expires_at_str)
                    if datetime.now() > expires_at:
                        # Cache expired, remove it and return None
                        os.remove(filepath)
                        return None
                else:
                    # No expiration metadata, consider it expired or invalid, remove
                    os.remove(filepath)
                    return None

                return cache_entry.get("data")
            except (IOError, json.JSONDecodeError) as e:
                print(f"Error reading or decoding cache file {filepath}: {e}")
                # Remove corrupted file
                if os.path.exists(filepath):
                    os.remove(filepath)
                return None

    def delete(self, key):
        filepath = self._get_filepath(key)
        with self.lock:
            if os.path.exists(filepath):
                try:
                    os.remove(filepath)
                    return True
                except IOError as e:
                    print(f"Error deleting cache file {filepath}: {e}")
                    return False
            return False

    def clear(self):
        with self.lock:
            for filename in os.listdir(self.cache_dir):
                filepath = os.path.join(self.cache_dir, filename)
                if os.path.isfile(filepath) and filepath.endswith('.json'):
                    try:
                        os.remove(filepath)
                    except IOError as e:
                        print(f"Error clearing cache file {filepath}: {e}")

