from flask import Flask, request, jsonify

app = Flask(__name__)
# Initialize the cache with a default expiration of 30 minutes
cache = DiskCache(cache_dir='flask_api_cache', default_expiration_minutes=30)

# Simulate an expensive API call
def fetch_expensive_data(item_id):
    print(f"Fetching data for item {item_id} from external API...")
    time.sleep(2) # Simulate network delay and processing
    return {
        "id": item_id,
        "name": f"Product {item_id}",
        "price": float(item_id) * 10.5,
        "details": {
            "description": f"This is a detailed description for product {item_id}.",
            "features": [f"featureA_{item_id}", f"featureB_{item_id}"]
        },
        "timestamp": datetime.now().isoformat()
    }

@app.route('/api/data/<item_id>')
def get_data(item_id):
    cache_key = f"api_data_{item_id}"
    data = cache.get(cache_key)

    if data:
        print(f"Serving data for item {item_id} from cache.")
        return jsonify(data)
    else:
        print(f"Cache miss for item {item_id}. Fetching from source.")
        # Fetch from the expensive source
        fetched_data = fetch_expensive_data(item_id)
        # Store in cache for 5 minutes (overriding default 30 min)
        cache.set(cache_key, fetched_data, expiration_seconds=5*60)
        return jsonify(fetched_data)

@app.route('/api/data/<item_id>/refresh', methods=['POST'])
def refresh_data(item_id):
    cache_key = f"api_data_{item_id}"
    print(f"Forcing refresh for item {item_id}.")
    fetched_data = fetch_expensive_data(item_id)
    cache.set(cache_key, fetched_data, expiration_seconds=5*60)
    return jsonify({"message": f"Data for item {item_id} refreshed and cached.", "data": fetched_data})

@app.route('/api/cache/clear', methods=['POST'])
def clear_all_cache():
    cache.clear()
    return jsonify({"message": "All cache entries cleared."})

@app.route('/api/cache/<item_id>/delete', methods=['DELETE'])
def delete_item_cache(item_id):
    cache_key = f"api_data_{item_id}"
    if cache.delete(cache_key):
        return jsonify({"message": f"Cache entry for {item_id} deleted."})
    else:
        return jsonify({"message": f"Cache entry for {item_id} not found or could not be deleted."}), 404

